import React, { useState } from 'react';
import './Header.css';

const Header = () => {
  const [isOpen, setIsOpen] = useState(false);

  const toggleMenu = () => setIsOpen(!isOpen);

  return (
    <header className="fixed top-0 left-0 w-full bg-white shadow-md z-50">
      <div className="container mx-auto flex items-center justify-between p-4">
        <h1 className="text-xl font-bold">Yusef Turin</h1>
        <nav className="hidden md:flex space-x-6">
          {["About", "Projects", "Contact"].map((item) => (
            <a key={item} href={`#${item.toLowerCase()}`} className="hover:text-gray-600">
              {item}
            </a>
          ))}
        </nav>
        <button className="md:hidden" onClick={toggleMenu} style={{ fontSize: "24px", background: "none", border: "none" }}>
          {isOpen ? "✖" : "☰"}
        </button>
      </div>
      {isOpen && (
        <div className="md:hidden bg-white shadow-md absolute top-full left-0 w-full p-4 flex flex-col space-y-4" style={{ transition: "opacity 0.3s ease-in-out" }}>
          {["About", "Projects", "Contact"].map((item) => (
            <a key={item} href={`#${item.toLowerCase()}`} className="hover:text-gray-600">
              {item}
            </a>
          ))}
        </div>
      )}
    </header>
  );
};

export default Header;